prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?between ?betweenName WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "2f572d235e784b838fa0d7d2a56748ab" .
  }
  UNION
  {
    ?model tai:originalId "2f572d235e784b838fa0d7d2a56748ab" .
  }

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?start a bboExt:ChoreographyTask ;
         bbo:name ?startName ;
         tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?startName)), "process provision"))

  ?end a bboExt:ChoreographyTask ;
       bbo:name ?endName ;
       tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?endName)), "operations provision"))

  # between = reachable from start, and end is reachable from between
  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?between .
  ?between ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .

  ?between bbo:name ?betweenName .

  FILTER(?between != ?start && ?between != ?end)
}
LIMIT 25

